app = Flask(__name__)

BACKEND_BASE_URL = os.getenv("BACKEND_BASE_URL", "http://localhost:5001")
FORWARD_HEADERS = {
    "content-type",
    "accept",
    "x-request-id",
    "x-correlation-id",
    "user-agent",
}

def get_bearer_token():
    auth_header = request.headers.get("Authorization", "")
    parts = auth_header.split()
    if len(parts) == 2 and parts[0].lower() == "bearer":
        return parts[1]
    return None

def decode_and_validate_jwt(token):
    try:
        unverified_header = jwt.get_unverified_header(token)
        alg = unverified_header.get("alg")
        if not alg or alg.lower() == "none":
            raise jwt.InvalidTokenError("Invalid signing algorithm")
        claims = jwt.decode(
            token,
            options={
                "verify_signature": False,
                "verify_exp": True,
                "verify_nbf": True,
                "verify_iat": True,
                "verify_aud": False,
                "verify_iss": False,
            },
            algorithms=[alg],
        )
        return claims
    except jwt.PyJWTError as e:
        raise ValueError(str(e))

def build_forward_headers(claims, token):
    headers = {}
    for key, value in request.headers.items():
        if key.lower() in FORWARD_HEADERS:
            headers[key] = value

    headers["Authorization"] = f"Bearer {token}"

    subject = claims.get("sub")
    if subject is not None:
        headers["X-User-Sub"] = str(subject)

    email = claims.get("email")
    if email is not None:
        headers["X-User-Email"] = str(email)

    roles = claims.get("roles") or claims.get("role")
    if roles is not None:
        if isinstance(roles, (list, tuple)):
            headers["X-User-Roles"] = ",".join(map(str, roles))
        else:
            headers["X-User-Roles"] = str(roles)

    return headers

def forward_request(path):
    token = get_bearer_token()
    if not token:
        return jsonify({"error": "Missing bearer token"}), 401

    try:
        claims = decode_and_validate_jwt(token)
    except ValueError as e:
        return jsonify({"error": "Invalid token", "details": str(e)}), 401

    target_url = urljoin(BACKEND_BASE_URL.rstrip("/") + "/", path.lstrip("/"))
    headers = build_forward_headers(claims, token)

    params = request.args.to_dict(flat=False)
    body = request.get_data()
    method = request.method

    resp = requests.request(
        method=method,
        url=target_url,
        headers=headers,
        params=params,
        data=body,
        cookies=request.cookies,
        allow_redirects=False,
        timeout=30,
    )

    excluded_response_headers = {
        "content-encoding",
        "content-length",
        "transfer-encoding",
        "connection",
    }

    response_headers = [
        (name, value)
        for name, value in resp.headers.items()
        if name.lower() not in excluded_response_headers
    ]

    return resp.content, resp.status_code, response_headers

